    "description": "Retrieves the current status of the reconciliation, including the count of unmatched ledger entries, unmatched bank statements, and the number of entries in the discrepancy log.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "unmatched_ledger_count": 10,
      "unmatched_bank_count": 4,
      "logged_discrepancies_count": 0
    }
  },
  "get_tax_rate_schedule": {
    "description": "Retrieves the official SUTA tax rate schedule for a specific period to identify rate changes and effective dates.",
    "parameters": {
      "type": "object",
      "properties": {
        "tax_type": {
          "type": "string",
          "description": "The type of tax (e.g., 'SUTA')."
        },
        "period": {
          "type": "string",
          "description": "The fiscal period (e.g., 'Q2')."
        }
      },
      "required": [
        "tax_type",
        "period"
      ]
    },
    "example_output": [
      {
        "effective_date": "202X-04-01",
        "rate": 0.021
      },
      {
        "effective_date": "202X-05-01",
        "rate": 0.027
      }
    ]
  },
  "get_ledger_entries": {
    "description": "Fetches internal ledger records for a specific account and period. Includes ID, date, amount, and current reconciliation status.",
    "parameters": {
      "type": "object",
      "properties": {
        "account_id": {
          "type": "string",
          "description": "The account number (e.g., '2210')."
        },
        "period": {
          "type": "string",
          "description": "The fiscal period (e.g., 'Q2')."
        },
        "status": {
          "type": "string",
          "enum": [
            "unreconciled",
            "reconciled",
            "all"
          ],
          "description": "Filter by reconciliation status."
        }
      },
      "required": [
        "account_id",
        "period"
      ]
    },
    "example_output": [
      {
        "id": "L-101",
        "date": "202X-05-15",
        "amount": 210.0,
        "description": "SUTA Accrual"
      }
    ]
  },
  "get_bank_statements": {
    "description": "Retrieves bank statement records for a specific period.",
    "parameters": {
      "type": "object",
      "properties": {
        "period": {
          "type": "string"
        },
        "status": {
          "type": "string",
          "enum": [
            "unreconciled",
            "reconciled",
            "all"
          ]
        }
      },
      "required": [
        "period"
      ]
    },
    "example_output": [
      {
        "id": "B-500",
        "date": "202X-05-20",
        "amount": -550.0
      }
    ]
  },
  "get_payroll_source_records": {
    "description": "Retrieves source payroll data including taxable wages per pay period to calculate expected tax liabilities.",
    "parameters": {
      "type": "object",
      "properties": {
        "period": {
          "type": "string"
        }
      },
      "required": [
        "period"
      ]
    },
    "example_output": [
      {
        "pay_date": "202X-05-15",
        "taxable_wages": 10000.0
      }
    ]
  },
  "match_entries": {
    "description": "Links a ledger entry and a bank record as a standard match, updating status to reconciled.",
    "parameters": {
      "type": "object",
      "properties": {
        "ledger_id": {
          "type": "string"
        },
        "bank_id": {
          "type": "string"
        }
      },
      "required": [
        "ledger_id",
        "bank_id"
      ]
    },
    "example_output": {
      "status": "success"
    }
  },
  "create_ledger_entry": {
    "description": "Manually adds a missing entry to the internal ledger to account for cash outflows found only in the bank statement.",
    "parameters": {
      "type": "object",
      "properties": {
        "account_id": {
          "type": "string"
        },
        "amount": {
          "type": "number"
        },
        "date": {
          "type": "string"
        },
        "description": {
          "type": "string"
        }
      },
      "required": [
        "account_id",
        "amount",
        "date",
        "description"
      ]
    },
    "example_output": {
      "new_ledger_id": "L-MANUAL-999"
    }
  },
  "resolve_ledger_entry": {
    "description": "Updates a ledger entry to 'reconciled' status and simultaneously logs the variance in the discrepancy list with a required justification.",
    "parameters": {
      "type": "object",
      "properties": {
        "ledger_id": {
          "type": "string"
        },
        "discrepancy_type": {
          "type": "string",
          "enum": [
